			},
		},
		{
			name:        "load_nonexistent_persona",
			personaName: "nonexistent-persona",
			expectError: true,
			validate:    nil,
		},
		{
			name:        "load_invalid_persona",
			personaName: "invalid-persona",
			expectError: true,
			validate:    nil,
		},

