   168	// buildPersonasSection creates the personas section content
   169	func (c *ClaudeInjectorImpl) buildPersonasSection(personas map[string]*Persona) string {
   170		var sections []string
   171	
   172		sections = append(sections, PersonasStartMarker)
   173		sections = append(sections, PersonasHeader)
   174		sections = append(sections, "")
   175	
   176		// Sort roles for consistent output (optional, but helpful for testing)
   177		roles := make([]string, 0, len(personas))
   178		for role := range personas {
   179			roles = append(roles, role)
   180		}
   181		sort.Strings(roles)
   182	
   183		for _, role := range roles {
   184			persona := personas[role]
   185			roleDisplay := formatRoleDisplay(role)
   186			personaHeader := fmt.Sprintf("### %s: %s", roleDisplay, persona.Name)
   187			sections = append(sections, personaHeader)
   188			sections = append(sections, persona.Content)
   189			sections = append(sections, "")
   190		}
   191	
   192		sections = append(sections, PersonasFooter)
   193		sections = append(sections, PersonasEndMarker)
   194	
   195		return strings.Join(sections, "\n")
   196	}
   197	
   198	// extractRolePersonaPairs extracts role->persona mappings from the content
   199	func (c *ClaudeInjectorImpl) extractRolePersonaPairs(content string) map[string]string {
   200		pairs := make(map[string]string)
   201	
   202		// Find personas section
   203		startIdx := strings.Index(content, PersonasStartMarker)
   204		if startIdx == -1 {
   205			return pairs
   206		}
   207	
   208		endIdx := strings.Index(content[startIdx:], PersonasEndMarker)
   209		if endIdx == -1 {
   210			return pairs
   211		}
   212	
   213		// Extract personas section
   214		endIdx = startIdx + endIdx
   215		personasSection := content[startIdx:endIdx]
   216	
   217		// Parse role and persona names using regex
   218		// Format: "### Role: persona-name" - must be at start of line
   219		personaPattern := regexp.MustCompile(`(?m)^###\s+([^:]+):\s+([^\n]+)`)
   220		matches := personaPattern.FindAllStringSubmatch(personasSection, -1)
   221	
   222		for _, match := range matches {
   223			if len(match) > 2 {
   224				role := strings.TrimSpace(match[1])
   225				personaName := strings.TrimSpace(match[2])
   226				if role != "" && personaName != "" {
   227					pairs[role] = personaName
   228				}
   229			}
   230		}
   231	
   232		return pairs
   233	}
   234	
   235	// formatRoleDisplay formats a role name for display (e.g., "code-reviewer" -> "Code Reviewer")
   236	func formatRoleDisplay(role string) string {
   237		if role == "" {
   238			return ""
   239		}
   240	
   241		// Replace separators with spaces and title case each word
   242		words := regexp.MustCompile(`[-_]+`).Split(role, -1)
   243		var formattedWords []string
   244	
   245		for _, word := range words {
   246			if word != "" {
   247				// Title case: first letter uppercase, rest lowercase
   248				if len(word) == 1 {
   249					formattedWords = append(formattedWords, strings.ToUpper(word))
   250				} else {
   251					formatted := strings.ToUpper(word[:1]) + strings.ToLower(word[1:])
   252					formattedWords = append(formattedWords, formatted)
   253				}
   254			}
   255		}
   256	
   257		return strings.Join(formattedWords, " ")
   258	}
