   758	// parsePersonaMetadata parses YAML frontmatter from persona content
   759	func parsePersonaMetadata(content string) *PersonaMetadata {
   760		lines := strings.Split(content, "\n")
   761		if len(lines) == 0 || lines[0] != "---" {
   762			return nil
   763		}
   764	
   765		// Find end of frontmatter
   766		endIdx := -1
   767		for i := 1; i < len(lines); i++ {
   768			if lines[i] == "---" {
   769				endIdx = i
   770				break
   771			}
   772		}
   773	
   774		if endIdx == -1 {
   775			return nil
   776		}
   777	
   778		// Parse YAML frontmatter
   779		frontmatter := strings.Join(lines[1:endIdx], "\n")
   780		var metadata PersonaMetadata
   781		if err := yaml.Unmarshal([]byte(frontmatter), &metadata); err != nil {
   782			return nil
   783		}
   784	
   785		return &metadata
   786	}
   787	
   788	// validatePersonaContent validates persona content structure
   789	func validatePersonaContent(content, personaName string) error {
   790		if strings.HasPrefix(content, "---\n") {
   791			// Try to parse the frontmatter to validate it
   792			lines := strings.Split(content, "\n")
   793			endIdx := -1
   794			for i := 1; i < len(lines); i++ {
   795				if lines[i] == "---" {
   796					endIdx = i
   797					break
   798				}
   799			}
   800			if endIdx > 0 {
   801				frontmatter := strings.Join(lines[1:endIdx], "\n")
   802				var metadata PersonaMetadata
   803				if err := yaml.Unmarshal([]byte(frontmatter), &metadata); err != nil {
   804					return fmt.Errorf("failed to parse YAML frontmatter in persona '%s': %w", personaName, err)
   805				}
   806			}
   807		}
   808		return nil
   809	}
