283	// getExistingPersonas extracts existing personas from CLAUDE.md
284	func (c *ClaudeInjectorImpl) getExistingPersonas() map[string]*Persona {
285		personas := make(map[string]*Persona)
286	
287		if !fileExists(c.claudeFilePath) {
288			return personas
289		}
290	
291		content, err := os.ReadFile(c.claudeFilePath)
292		if err != nil {
293			return personas
294		}
295	
296		// Find personas section
297		contentStr := string(content)
298		startIdx := strings.Index(contentStr, PersonasStartMarker)
299		if startIdx == -1 {
300			return personas
301		}
302	
303		endIdx := strings.Index(contentStr[startIdx:], PersonasEndMarker)
304		if endIdx == -1 {
305			return personas
306		}
307	
308		// Extract personas section content
309		endIdx = startIdx + endIdx
310		personasSection := contentStr[startIdx:endIdx]
311	
312		// Find persona entries using regex (simpler pattern)
313		lines := strings.Split(personasSection, "\n")
314		var currentRole, currentPersona string
315		var contentLines []string
316		inPersona := false
317	
318		for _, line := range lines {
319			line = strings.TrimSpace(line)
320	
321			// Check if this is a persona header line
322			if strings.HasPrefix(line, "### ") {
323				// Save previous persona if we have one
324				if inPersona && currentRole != "" && currentPersona != "" && len(contentLines) > 0 {
325					content := strings.TrimSpace(strings.Join(contentLines, "\n"))
326					if content != "" {
327						role := formatRoleFromDisplay(currentRole)
328						personas[role] = &Persona{
329							Name:    currentPersona,
330							Roles:   []string{role},
331							Content: content,
332						}
333					}
334				}
335	
336				// Parse new persona header
337				headerText := strings.TrimPrefix(line, "### ")
338				parts := strings.SplitN(headerText, ":", 2)
339				if len(parts) == 2 {
340					currentRole = strings.TrimSpace(parts[0])
341					currentPersona = strings.TrimSpace(parts[1])
342					contentLines = []string{}
343					inPersona = true
344				} else {
345					inPersona = false
346				}
347			} else if inPersona && line != "" && !strings.Contains(line, "When responding, adopt the appropriate persona") {
348				// Add content line
349				contentLines = append(contentLines, line)
350			}
351		}
352	
353		// Save the last persona
354		if inPersona && currentRole != "" && currentPersona != "" && len(contentLines) > 0 {
355			content := strings.TrimSpace(strings.Join(contentLines, "\n"))
356			if content != "" {
357				role := formatRoleFromDisplay(currentRole)
358				personas[role] = &Persona{
359					Name:    currentPersona,
360					Roles:   []string{role},
361					Content: content,
362				}
363			}
364		}
365	
366		return personas
367	}
